using System.Text;
using System.Text.RegularExpressions;
using BenchmarkDotNet.Attributes;

[MemoryDiagnoser( false )]
[HideColumns(
  "Job",
  "Error",
  "StdDev",
  "Median",
  "RatioSD",
  "y"
)]
public partial class MacroProcessingBenchmarks
{
